/* eslint-disable @typescript-eslint/naming-convention */
/**
Options for querying the terminal.
*/
export type QueryTerminalOptions = {
	/**
	Time to wait for response in milliseconds.
	*/
	readonly timeoutMilliseconds?: number;

	/**
	Terminator used to finish early.
	*/
	readonly responseTerminator?: string | RegExp;

	/**
	Input stream to read from.
	*/
	readonly stdin?: NodeJS.ReadStream;

	/**
	Output stream to write to.
	*/
	readonly stdout?: NodeJS.WriteStream;
};

export type QueryTerminalHelperOptions = Omit<
	QueryTerminalOptions,
	'responseTerminator'
>;

export type QueryTerminalSyncOptions = Omit<QueryTerminalOptions, 'stdin'>;

export type QueryTerminalSyncHelperOptions = Omit<
	QueryTerminalSyncOptions,
	'responseTerminator'
>;

/**
Send an escape sequence to the terminal and return the response.

@param query - The escape sequence to send.
@param options - Options including timeout.
@returns The response, or `undefined` if not in a TTY or no response is received.

@example
```
import {queryTerminal} from 'terminal-query';

const response = await queryTerminal('\u001B[>q', {timeoutMilliseconds: 100});
console.log(response);
```
*/
export function queryTerminal(
	query: string,
	options?: QueryTerminalOptions,
): Promise<string | undefined>;

/**
Query terminal name and version (XTVERSION).

Returns the payload (text between `DCS >|` and `ST`) when available. If parsing fails, it returns `undefined`.

@example
```
import {queryXTVERSION} from 'terminal-query';

const version = await queryXTVERSION();
console.log(version);
//=> 'iTerm2 3.5.0'
```
*/
export function queryXTVERSION(
	options?: QueryTerminalHelperOptions,
): Promise<string | undefined>;

/**
Query terminfo capabilities (XTGETTCAP).

@throws {TypeError} If `capabilityNames` is empty.

@example
```
import {queryXTGETTCAP} from 'terminal-query';

const response = await queryXTGETTCAP('indn');
console.log(response);
```
*/
export function queryXTGETTCAP(
	capabilityNames: string | string[],
	options?: QueryTerminalHelperOptions,
): Promise<string | undefined>;

/**
Query primary device attributes (DA1).

@example
```
import {queryDeviceAttributes} from 'terminal-query';

const response = await queryDeviceAttributes();
console.log(response);
```
*/
export function queryDeviceAttributes(
	options?: QueryTerminalHelperOptions,
): Promise<string | undefined>;

/**
Query iTerm2 feature reporting (`OSC 1337;Capabilities`).

@example
```
import {queryITermFeatures} from 'terminal-query';

const response = await queryITermFeatures();
console.log(response);
```
*/
export function queryITermFeatures(
	options?: QueryTerminalHelperOptions,
): Promise<string | undefined>;

